    font-size: 1.2rem;
    background-color: #4CAF50;
    color: white;
    border: none;
    border-radius: 25px;
    cursor: pointer;
    transition: background-color 0.3s ease;
    animation: slideInUp 0.8s ease-out 0.3s both;
}

#start-btn-welcome:hover {
    background-color: #45a049;
}

/* Score Animation */
#score {
    animation: popIn 0.3s ease-out;
}

@keyframes popIn {
    from { transform: scale(0.8); opacity: 0; }
    to { transform: scale(1); opacity: 1; }
}

/* Responsive adjustments */
@media (max-width: 480px) {
    #game-container {
        width: 320px;
        height: 520px;
    }
    button {
        font-size: 14px;
        padding: 10px 18px;
    }
    #score, #history {
        font-size: 14px;
        padding: 6px 12px;
    }
    #welcome-screen h1 {
        font-size: 2.2rem;
    }
    #welcome-screen p {
        font-size: 1rem;
    }
